```java
import java.util.ArrayList;
import java.util.List;

public class Inventory {
    private List<Item> items;

    public Inventory() {
        this.items = new ArrayList<>();
    }

    public void addItem(Item item) {
        items.add(item);
        System.out.println("Item added: " + item.getName());
    }

    public void removeItem(String itemName) {
        items.removeIf(item -> item.getName().equalsIgnoreCase(itemName));
        System.out.println("Item removed: " + itemName);
    }

    public void searchItem(String itemName) {
        for (Item item : items) {
            if (item.getName().equalsIgnoreCase(itemName)) {
                System.out.println("Item found: " + item.toString());
                return;
            }
        }
        System.out.println("Item not found: " + itemName);
    }

    public void updateQuantity(String itemName, int newQuantity) {
        for (Item item : items) {
            if (item.getName().equalsIgnoreCase(itemName)) {
                item.setQuantity(newQuantity);
                System.out.println("Quantity updated for: " + itemName);
                return;
            }
        }
        System.out.println("Item not found: " + itemName);
    }

    public void displayInventory() {
        if (items.isEmpty()) {
            System.out.println("Inventory is empty.");
        } else {
            for (Item item : items) {
                System.out.println(item.toString());
            }
        }
    }
}
```

#### Main.java (updated)

```java
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Inventory inventory = new Inventory();
        Scanner scanner = new Scanner(System.in);

        while (true) {
            System.out.println("\nInventory Management System");
            System.out.println("1. Add Item");
            System.out.println("2. Remove Item");
            System.out.println("3. Search Item");
            System.out.println("4. Update Quantity");
            System.out.println("5. Display Inventory");
            System.out.println("6. Exit");

            System.out.print("Choose an option: ");
            int option = scanner.nextInt();
            scanner.nextLine(); // Consume newline left-over

            switch (option) {
                case 1:
                    System.out.print("Enter item name: ");
                    String name = scanner.nextLine();
                    System.out.print("Enter quantity: ");
                    int quantity = scanner.nextInt();
                    System.out.print("Enter price: ");
                    double price = scanner.nextDouble();
                    scanner.nextLine(); // Consume newline left-over
                    inventory.addItem(new Item(name, quantity, price));
                    break;
                case 2:
                    System.out.print("Enter item name to remove: ");
                    String removeName = scanner.nextLine();
                    inventory.removeItem(removeName);
                    break;
                case 3:
                    System.out.print("Enter item name to search: ");
                    String searchName = scanner.nextLine();
                    inventory.searchItem(searchName);
                    break;
                case 4:
                    System.out.print("Enter item name to update quantity: ");
                    String updateName = scanner.nextLine();
                    System.out.print("Enter new quantity: ");
                    int newQuantity = scanner.nextInt();
                    scanner.nextLine(); // Consume newline left-over
                    inventory.updateQuantity(updateName, newQuantity);
                    break;
                case 5:
                    inventory.displayInventory();
                    break;
                case 6:
                    System.out.println("Exiting...");
                    return;
                default:
                    System.out.println("Invalid option. Please choose again.");
            }
        }
    }
}
```

This updated code provides a simple text-based interface for managing the inventory. You can add, remove, search, and update items, as well as display the entire inventory.

